module median_filter(input [8:0] pixels, output reg [7:0] median);  
    integer i, j;  
    reg [7:0] obf_sorted[0:8];  
    reg [7:0] temp;  

    always @(*) begin  
        // Copy input pixels to obf_sorted array  
        for (i = 0; i < 9; i = i + 1)  
            obf_sorted[i] = pixels[i];  

        // Simple bubble sort to sort the pixel values  
        for (i = 0; i < 8; i = i + 1) begin  
            for (j = 0; j < 8 - i; j = j + 1) begin  
                if (obf_sorted[j] > obf_sorted[j + 1]) begin  
                    temp = obf_sorted[j];  
                    obf_sorted[j] = obf_sorted[j + 1];  
                    obf_sorted[j + 1] = temp;  
                end  
            end  
        end  

        // The median is the middle value in the obf_sorted array  
        median = obf_sorted[4];  
    end  
endmodule
